class MathHelper {
    // Everything inside here belongs to the Class itself
    companion object {
        val PI = 3.14159
        fun add(a: Int, b: Int) = a + b
    }
}

fun main() {
    // Notice we DON'T create a MathHelper() object!
    // We access it directly through the uppercase Blueprint name.
    println(MathHelper.PI)
    println(MathHelper.add(5, 10))
}
